  `check_out_lng` decimal(11,8) DEFAULT NULL,
  `check_out_address` varchar(300) DEFAULT NULL,
  `working_hours` decimal(5,2) DEFAULT NULL,
  `status` enum('PRESENT','ABSENT','HALF_DAY','LEAVE','WFH','FIELD_VISIT') NOT NULL DEFAULT 'PRESENT',
  `note` text DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_attendance` (`employee_id`,`date`),
  KEY `idx_att_date` (`date`),
  KEY `idx_att_status` (`status`),
  KEY `idx_att_emp_date` (`employee_id`,`date`),
  CONSTRAINT `fk_attendance_employee` FOREIGN KEY (`employee_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
